on_write:
let res = #{ action: "Allow" };
if !payload.contains("node_label") || !payload.contains("foreign_keys") {
    res.action = "Reject";
    res.reason = "Graph-Relational hybrid requires both node context and relational foreign keys";
}
res

on_read:
let res = #{ payload: payload };
if payload.node_label == query_key || payload.foreign_keys.contains(query_key) {
    res.match_found = true;
} else {
    res.match_found = false;
}
res
